def min_anagram_length(s: str) -> int:
    n = len(s)
    for length in range(1, n + 1):
        if n % length != 0:
            continue
        # Count characters in the first block
        from collections import Counter
        base_count = Counter(s[:length])
        # Check all subsequent blocks
        for i in range(length, n, length):
            if Counter(s[i:i+length]) != base_count:
                break
        else:
            return length
    return n
